head.script:
/* 
 * 참고사항
 * 1. 해당 화면 피벗 컴포넌트로 개발해야하나, 피벗 컴포넌트가 이상함(해더부분,subtotal도 미존재 ), 
 *    asis 테스트 결과 컬럼 수 변경이 없어 아래와 같이 개발.
 * 2. 동적으로 컬럼수 변경 케이스 발견시,
 *    히든 컬럼을 더 만들고 colData.length수를 더 늘리거나, 피벗 컴포넌트로 재개발 필요.-> 웹스퀘어에서는 동적으로 컬럼 그려주는것이 안되기 때문
 */

//-------------------------------------------------------------------------
// TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    // tobe변경 : 공통코드 넣어줬으나, asis랑 값이 다름...따라서 다이렉트로 셋해줌.
    // var codeOptions = [
    //     { grpCd : "ZZ202", compID : "lc_eqClssCd, gr_work_pl:eqClssCd"},
    // ];
    // $c.data.setCommonCode(codeOptions);

    lc_eqClssCd.setSelectedIndex(0);
    lc_eqClssCd.focus(); //초기포커스
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (e) {
    if( !(await $c.gus.cfValidate(tb_wrk))) return;

	//ds_fix_work_re.UseChangeInfo = false; // 조회조건

    dma_fix_work_re.set("eqClssCd", lc_eqClssCd.getValue());

	$c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = async function(e){
    if(e.responseJSON.resultDataSet[0].Msg != 'FAIL'){
        ds_crosstab.removeAll();
        var rowCnt = ds_fix_work_list.getRowCount();
        var crossRowCnt = 0;
        ds_fix_work_list.sort("eqClssCd", 0); //원래데이터 정렬

        if( rowCnt == 0 ){
            await $c.win.alert("조회된 데이터가 없습니다.");
            return;
        }else{
            //ds_crosstab 생성
            var colData = []; //컬럼

            var allJson = [];
            var rJson = {}; 
            var num = 0;

            //컬럼갯수(항목) 확인
            for(var i = 0; i < rowCnt; i++){
                var rowJson = ds_fix_work_list.getRowJSON(i);
                var lobranNmV = rowJson.lobranNm;

                if(!colData.includes(lobranNmV)){
                    colData.push(lobranNmV)
                }

                if(colData.length > 56) return; //해당 케이스 발견시, ds_crosstab생성 소스 지우고 피벗컴포넌트로 만들어야함. 웹스퀘어로 그리드 컬럼 동적으로 생성 없음. 

                var eqClssCdV = rowJson.eqClssCd;
                var eqCntV = rowJson.eqCnt
                var beforeEqClssCd = "";  // 전행의 구분값

                if(i >= 1){
                    var beforeRowJson = ds_fix_work_list.getRowJSON(i-1);
                    beforeEqClssCd = beforeRowJson.eqClssCd
                }

                if(eqClssCdV == beforeEqClssCd){
                    rJson[`eqCnt${num}`] = eqCntV;
                    num = num + 1;

                    if(i == rowCnt-1){
                        allJson.push(rJson); //마지막 행 담아줌
                    }

                }else{
                    if(i != 0){
                        allJson.push(rJson);
                        rJson = {};
                    }

                    num = 1;
                    rJson["eqCnt1"] = eqCntV;
                    rJson["eqClssCd"] = eqClssCdV;
                    num = num + 1;

                }
            }

            ds_crosstab.setJSON(allJson);
            crossRowCnt = ds_crosstab.getRowCount();

            for(var i = 0; i < colData.length; i++){ 
                gr_work_pl.setColumnVisible(`eqCnt${i+1}`, true);  //컬럼갯수에 맞게 show
                var colName = colData[i];

                if(colName.indexOf(";") != -1) colName = colName.replaceAll(";","<br>")

                gr_work_pl.setHeaderValue(`lobranNm${i+1}`, colName); //헤더 이름
            }
        }

        totalRow.setValue(crossRowCnt);

        gr_work_pl.setVisibleRowNum(16);
    }
};

//-------------------------------------------------------------------------
// 조회 조건 지우기
//-------------------------------------------------------------------------
scwin.f_FieldClear = function (e) {
    $c.gus.cfInitObjects(tb_wrk, null);

    lc_eqClssCd.setSelectedIndex(0);
};

//-------------------------------------------------------------------------
// List 엑셀파일로 저장
//-------------------------------------------------------------------------
scwin.f_toExcel1 = function(){
    var options = {
        fileName: "장비보유현황 조회.xlsx",
        sheetName: "장비보유현황 조회",
    };

    $c.data.downloadGridViewExcel(gr_work_pl, options);
};

